// ============================================================
// EXTRAI DADOS E SALVA - roda para TODAS as mensagens do grupo
// (independente de mencionar o bot)
// ============================================================
const body = $input.first().json;
const b = body.body || {};

// Green API
const gMsg = b.messageData || {};
const gText = gMsg.textMessageData?.textMessage || gMsg.extendedTextMessageData?.text || '';
const gSender = b.senderData?.senderName || b.senderData?.senderContactName || '';
const gMsgId = b.idMessage || gMsg.idMessage || '';
const gChat = b.senderData?.chatId || '';

// Evolution API
const eData = b.data || b || {};
const eMsg = eData.message || {};
const eText = eMsg.conversation || eMsg.extendedTextMessage?.text || eMsg.imageMessage?.caption || '';
const eSender = eData.pushName || '';
const eMsgId = eData.key?.id || '';
const eChat = eData.key?.remoteJid || '';

const textMessage = gText || eText;
const sender = gSender || eSender || 'Alguém';
const messageId = gMsgId || eMsgId || ('tmp_' + Date.now());
const chatId = gChat || eChat;

// Só salva se tiver texto
if (!textMessage) {
  return [];
}

return [{
  json: {
    dbRemetente: sender,
    dbMensagem: textMessage,
    messageId,
    chatId
  }
}];

// ============================================================
// VERIFICA MENÇÃO - só continua se o bot foi mencionado
// ============================================================
const body = $('Webhook').first().json;
const b = body.body || {};

// Green API
const gMsg = b.messageData || {};
const gText = gMsg.textMessageData?.textMessage || gMsg.extendedTextMessageData?.text || '';
const gChat = b.senderData?.chatId || '';

// Evolution API
const eData = b.data || b || {};
const eMsg = eData.message || {};
const eText = eMsg.conversation || eMsg.extendedTextMessage?.text || '';
const eChat = eData.key?.remoteJid || '';

const textMessage = gText || eText;
const chatId = gChat || eChat;
// Ignora mensagens antigas (histórico de sincronização da Evolution API)
const msgTimestamp = eData.messageTimestamp || 0;
const nowTimestamp = Math.floor(Date.now() / 1000);
if (msgTimestamp && (nowTimestamp - msgTimestamp) > 120) {
  return []; // mensagem com mais de 2 minutos, ignora
}

// Verifica menção de forma precisa (não usa fullContent para evitar falsos positivos)
const botNumbers = ['554396543242', '235437994062039'];

// 1. Checa mentionedJid (Evolution API)
const mentionedJids = eMsg.extendedTextMessage?.contextInfo?.mentionedJid ||
  eMsg.imageMessage?.contextInfo?.mentionedJid || [];
const isMentionedJid = mentionedJids.some(jid => botNumbers.some(n => jid.includes(n)));

// 2. Checa @menção no texto
const isMentionedText = botNumbers.some(n => textMessage.includes('@' + n) || textMessage.includes('@' + n.slice(2)));

// 3. Checa se é mensagem direta (não grupo)
const isDirectMessage = chatId && !chatId.includes('@g.us');

if (!isMentionedJid && !isMentionedText && !isDirectMessage) {
  return [];
}

const txtLower = textMessage.toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '');

// Detecta tipo de relatório
const isReportMensal = txtLower.includes('mensal') || txtLower.includes('mes') || txtLower.includes('mês');
const isReportSemanal = !isReportMensal && (txtLower.includes('semanal') || txtLower.includes('semana'));
const isReport = txtLower.includes('relatorio') || txtLower.includes('resumo');
const reportType = isReportMensal ? 'mensal' : isReportSemanal ? 'semanal' : 'diario';

const isTraining = txtLower.startsWith('claude aprenda') || txtLower.startsWith('claude correcao') ||
  textMessage.toLowerCase().includes('claude aprenda') || textMessage.toLowerCase().includes('claude correcao');

return [{ json: { chatId, textMessage, isReport, isTraining, reportType } }];

const rulesData = $('Busca Regras').all();
const rules = rulesData.map(r => r.json.regra).filter(Boolean).slice(0, 30).join('\n- ');
const rulesPrompt = rules ? '\n\n⚠️ REGRAS ADICIONAIS DE TREINAMENTO (Siga Rigorosamente):\n- ' + rules : '';

// Busca system prompt customizado do banco (cap at 40000 chars)
let systemPromptTemplate = null;
try {
  const spData = $('Busca System Prompt').all();
  let sp = spData[0]?.json?.valor || null;
  if (sp && sp.length > 40000) sp = sp.substring(0, 40000) + '\n[...truncado...]';
  systemPromptTemplate = sp;
} catch(e) {}

// Busca as últimas mensagens do grupo para contexto
let historicoData = [];
try { historicoData = $('Busca Histórico 10').all(); } catch(e) {}
let historico = '';
if (historicoData && historicoData.length > 0) {
  const msgs = historicoData.map(e => e.json);
  for (const msg of msgs) {
    let hora = '??:??';
    try {
      const d = new Date(new Date(msg.data_hora).getTime() - 3 * 60 * 60 * 1000);
      hora = d.toISOString().substring(11, 16);
    } catch(e) {}
    const msgTxt = (msg.mensagem || '').substring(0, 300);
    historico += `[${hora}] ${msg.remetente}: ${msgTxt}\n`;
  }
  if (historico.length > 3000) historico = historico.substring(historico.length - 3000);
}
const historicoSection = historico ? `\n\nÚLTIMAS MENSAGENS DO GRUPO (use como contexto para entender o assunto em andamento):\n${historico}` : '';

// Lê POPs direto do Postgres (múltiplos itens)
const popsArray = $input.all().map(i => i.json).filter(p => p.titulo && p.conteudo);
let colaboradoresArray = [];
try { colaboradoresArray = $('Busca Colaboradores').all().map(i => i.json).filter(c => c.nome); } catch(e) {}

let clientesContent = '';
const allNonClientPops = [];

for (const pop of popsArray) {
  const cat = (pop.categoria || '').toLowerCase();
  const isClientDB = cat.includes('cliente') || cat.includes('banco') || cat.includes('base') || cat.includes('crm');
  if (isClientDB) {
    clientesContent += pop.conteudo + '\n';
  } else {
    allNonClientPops.push(pop);
  }
}

let _vM; try { _vM = $('Verifica Menção').first().json; if (!_vM.chatId) _vM = null; } catch(e) {}
if (!_vM) try { _vM = $('Formata Transcrição').first().json; } catch(e) { _vM = {}; }
const chatId = _vM.chatId || '';
const textMessage = _vM.textMessage || '';

const now = new Date();
const brt = new Date(now.toLocaleString('en-US', { timeZone: 'America/Sao_Paulo' }));
const dia = brt.getDate().toString().padStart(2,'0');
const mes = (brt.getMonth()+1).toString().padStart(2,'0');
const ano = brt.getFullYear();
const today = `${ano}-${mes}-${dia}`;

const msgLower = textMessage.toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '');
const palavrasMsg = msgLower.split(/\s+/).filter(p => p.length > 2);

// Smart POP selection: injeta apenas POPs relevantes à mensagem atual
const matchedPops = allNonClientPops.filter(pop => {
  const titleNorm = pop.titulo.toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '');
  const contentPreview = (pop.conteudo || '').substring(0, 200).toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '');
  return palavrasMsg.some(w => w.length > 3 && (titleNorm.includes(w) || contentPreview.includes(w)));
});

const isListingPops = msgLower.includes('pop') || msgLower.includes('procedimento') || msgLower.includes('quais') || msgLower.includes('lista');
let pops = '';
if (matchedPops.length > 0 && !isListingPops) {
  // Injeta conteúdo completo só dos POPs relevantes
  for (const pop of matchedPops) {
    pops += '=== ' + pop.titulo + ' ===\n';
    pops += pop.conteudo.substring(0, 5000) + '\n\n';
  }
} else {
  // Apenas lista os títulos disponíveis
  const titulos = allNonClientPops.map(p => `- ${p.titulo} (${p.categoria || 'Geral'})`).join('\n');
  if (titulos) pops = 'POPs disponíveis (peça pelo nome para ver o conteúdo completo):\n' + titulos;
}

// Parser de clientes
const fonteClientes = clientesContent;
const clientesDB = [];
const linhas = fonteClientes.split('\n');
for (const linha of linhas) {
  let nome = '', cod = '';
  if (linha.includes('\t')) {
    const partes = linha.split('\t').map(p => p.trim());
    const ultimaParte = partes[partes.length - 1];
    if (/^\d+$/.test(ultimaParte)) { cod = ultimaParte; nome = partes[0]; }
  }
  if (!cod) {
    const m = linha.match(/^(.+?)\s{1,}(\d{1,6})\s*$/);
    if (m) { nome = m[1].trim(); cod = m[2].trim(); }
  }
  if (nome && cod && !/^(nome|cód|cod|cliente|código)$/i.test(nome)) {
    clientesDB.push({ nome, cod, nomeLower: nome.toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '') });
  }
}

const clientesEncontrados = [];
const idsAdicionados = new Set();
for (const cliente of clientesDB) {
  for (const palavra of palavrasMsg) {
    if (cliente.nomeLower.includes(palavra) && !idsAdicionados.has(cliente.cod)) {
      clientesEncontrados.push(cliente.cod + ' - ' + cliente.nome);
      idsAdicionados.add(cliente.cod);
      break;
    }
  }
}

const clienteInfo = clientesEncontrados.length > 0
  ? 'CLIENTES ENCONTRADOS NA BUSCA: ' + clientesEncontrados.join(' | ')
  : 'NENHUM CLIENTE ENCONTRADO COM ESSE NOME';

const colaboradoresStr = colaboradoresArray.length > 0
  ? 'COLABORADORES DA EQUIPE:\n' + colaboradoresArray.map(c => `- ${c.nome}${c.cargo ? ' (' + c.cargo + ')' : ''}${c.funcoes ? ': ' + c.funcoes : ''}`).join('\n')
  : '';

let systemContent;
if (systemPromptTemplate && systemPromptTemplate !== '__RESET_TO_DEFAULT__') {
  systemContent = systemPromptTemplate
    .replace(/\{\{DATA\}\}/g, `${dia}/${mes}/${ano}`)
    .replace(/\{\{ANO\}\}/g, String(ano))
    .replace(/\{\{TODAY\}\}/g, today)
    .replace(/\{\{COLABORADORES\}\}/g, colaboradoresStr)
    .replace(/\{\{CLIENTES\}\}/g, clienteInfo)
    .replace(/\{\{POPS\}\}/g, pops)
    .replace(/\{\{HISTORICO\}\}/g, historicoSection);
  systemContent = rulesPrompt + '\n' + systemContent;
} else {
  systemContent = rulesPrompt + '\nVocê é o assistente interno da Zazz Internet, provedor de fibra óptica em Lunardelli-PR. Seu nome é Maluco da IA 👽🍀. Use o emoji 🍀 ocasionalmente.\n\nDATA ATUAL: ' + dia + '/' + mes + '/' + ano + ' (' + today + '). O ANO ATUAL É ' + ano + '. Quando alguém disser "amanhã", calcule a partir de ' + dia + '/' + mes + '/' + ano + '. NUNCA use datas de 2024 ou 2025.\n\nFORMATAÇÃO OBRIGATÓRIA (WhatsApp):\n- Negrito: use *texto* (UM asterisco de cada lado)\n- Itálico: use _texto_ (underline de cada lado)\n- PROIBIDO usar ** ## ### ou blocos de código\n- Para passos, use números: 1. 2. 3.\n- Use emojis: 📌 ✅ ⚠️\n\n' + colaboradoresStr + '\n\n' + clienteInfo + '\n⚠️ REGRA CRÍTICA DE CLIENTES (SIGA RIGOROSAMENTE - PRIORIDADE MÁXIMA):\n- Analise a lista de CLIENTES ENCONTRADOS acima\n- Se houver APENAS 1 cliente na lista, use esse cliente normalmente\n- Se houver MAIS DE 1 cliente na lista, você é PROIBIDO de escolher um sozinho. Você DEVE listar TODOS os clientes encontrados numerados e PERGUNTAR ao colaborador qual é o correto\n- NÃO crie a tarefa no Notion até o colaborador confirmar qual cliente é o correto\n- Se aparecer NENHUM CLIENTE ENCONTRADO, diga que não encontrou e peça o nome completo ou código\n- NUNCA invente códigos ou nomes de clientes\n\nPROCEDIMENTOS OPERACIONAIS / POPs DA EMPRESA:\n' + pops + '\nSe perguntarem "quais POPs você tem" ou "quais procedimentos existem", liste os títulos acima.\n' + historicoSection + '\n\nCRIAÇÃO DE TAREFAS:\nQuando pedirem para agendar/criar/registrar, responda com:\n\n|||NOTION|||\n{"descricao": "descrição da tarefa", "cliente": "código - nome completo", "tipo": "Internet", "status": "Parado", "responsavel": "nome do responsável informado", "data": "' + today + '", "entrega": "YYYY-MM-DD", "obs": "detalhes adicionais", "fone": "telefone ou vazio"}\n|||FIM|||\n\nDepois do JSON, confirme no WhatsApp. Se não for tarefa, responda normalmente.';
}

return [{
  json: {
    chatId: chatId,
    claudeBody: {
      model: "claude-haiku-4-5-20251001",
      max_tokens: 2048,
      system: systemContent,
      messages: [{"role": "user", "content": textMessage}]
    }
  }
}];

