let _vM; try { _vM = $('Verifica Menção').first().json; if (!_vM.chatId) _vM = null; } catch(e) {}
if (!_vM) try { _vM = $('Formata Transcrição').first().json; } catch(e) { _vM = {}; }
const chatId = _vM.chatId || '';
const reportType = _vM.reportType || 'diario';
const dbResults = $input.all().map(e => e.json);

const periodoLabel = reportType === 'mensal'
  ? 'DO MÊS (últimos 30 dias)'
  : reportType === 'semanal'
  ? 'DA SEMANA (últimos 7 dias)'
  : 'DE HOJE';

let historico = '';
for (const msg of dbResults) {
  let hora = '??:??';
  let data = '??/??';
  try {
    const d = new Date(new Date(msg.data_hora).getTime() - 3 * 60 * 60 * 1000);
    hora = d.toISOString().substring(11, 16);
    data = d.toISOString().substring(8, 10) + '/' + d.toISOString().substring(5, 7);
  } catch(e) {}

  const prefixo = (reportType === 'semanal' || reportType === 'mensal') ? `[${data} ${hora}]` : `[${hora}]`;
  historico += `${prefixo} ${msg.remetente}: ${msg.mensagem}\n`;
}

const now = new Date();
const brt = new Date(now.toLocaleString('en-US', { timeZone: 'America/Sao_Paulo' }));
const dia = brt.getDate().toString().padStart(2,'0');
const mes = (brt.getMonth()+1).toString().padStart(2,'0');
const ano = brt.getFullYear();
const today = `${ano}-${mes}-${dia}`;

return [{
  json: {
    chatId: chatId,
    claudeBody: {
      model: "claude-haiku-4-5-20251001",
      max_tokens: 4096,
      system: ` ${rulesPrompt}\nVocê é Maluco da IA 👽🍀. DATA ATUAL: ${dia}/${mes}/${ano}.\nO usuário solicitou um RELATÓRIO ${periodoLabel} com base nas mensagens do grupo.\nLeia o histórico de conversas do grupo abaixo e crie um resumo profissional e claro.\nListe:\n1. Serviços Solicitados e Concluídos\n2. Serviços que ficaram Pendentes (se houver)\n3. Principais destaques do período\n${reportType !== 'diario' ? '4. Tendências ou padrões observados no período\n' : ''}\nFormatação WhatsApp: *negrito*, _itálico_, emojis 🟢🟡🔴. NÃO use ## ou **.\n\nHISTÓRICO DO GRUPO ${periodoLabel}:\n${historico.substring(0, 20000)}\n`,
      messages: [{"role": "user", "content": `Gere o relatório ${periodoLabel.toLowerCase()} por favor!`}]
    }
  }
}];

