  id SERIAL PRIMARY KEY,
  data_hora TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
  message_id VARCHAR(100) UNIQUE,
  remetente VARCHAR(100),
  mensagem TEXT,
  chat_id VARCHAR(100)
);
