CREATE INDEX IF NOT EXISTS idx_mensagens_data_hora ON mensagens(data_hora);
DO $$ BEGIN IF NOT EXISTS (SELECT 1 FROM pg_constraint WHERE conname = 'mensagens_message_id_key') THEN ALTER TABLE mensagens ADD CONSTRAINT mensagens_message_id_key UNIQUE (message_id); END IF; END $$;
CREATE TABLE IF NOT EXISTS regras (
  id SERIAL PRIMARY KEY,
  regra TEXT NOT NULL
);

